            reference: "FSSAI Manual Method 2.1.9",
            procedure: `
              <h4 class="font-semibold mt-4 mb-2">Hehner's Test:</h4>
              <ol class="list-decimal list-outside pl-5 space-y-2">
                <li>Ek test tube mein 10 ml doodh lein.</li>
                <li>5 ml concentrated sulphuric acid (with trace of ferric chloride вҖ” 0.2 ml of 10% FeClвӮғ per 100 ml acid) ko tube ki deewar se carefully neeche slide karein taaki ye doodh ke neeche settle ho jaye.</li>
                <li>Interface (junction) par colour observe karein.</li>
              </ol>

              <h4 class="font-semibold mt-4 mb-2">Result:</h4>
              <p><strong>Violet/Purple ring at junction:</strong> Formalin PRESENT вҖ” adulterated</p>
              <p><strong>Brown ring (normal):</strong> Formalin ABSENT вҖ” no adulteration</p>

              <h4 class="font-semibold mt-4 mb-2">Confirmatory Test (Chromotropic Acid Test):</h4>
              <p>1 ml doodh + 1 ml chromotropic acid solution + 5 ml conc. HвӮӮSOвӮ„. Violet colour = formaldehyde confirmed.</p>
            `
